#include<bits/stdc++.h>
using namespace std;
void print(int s){
	int day=(s/86400)+1;s%=86400;
	int h=(s/3600);s%=3600;
	int min=s/60;s%=60;
	printf("202304%02dat%02d:%02d:%02d",day,h,min,s); 
}
int main(void){
	int T[100005],S,n,v0,v1,v2,t1,t2,i=0,d=0,e,p;
	cin>>S>>v0>>v1>>t1>>v2>>t2>>n;
	for(int i=0;i<n;i++)cin>>T[i];
	T[n]=2100000000;
	while(true){
		if(d+(long long)(T[i]-p)*v0>=S){
			print((S-d)/v0+((S-d)%v0!=0)+p);
			return false;
		}
		d+=(T[i]-p)*v0,d=max(0,d-v1*t1),p=T[i]+t1;v1+=v2,t1+=t2;
		i++;
	}
	return false;
}
